                            IsSimp = 1 	# Mapping has been simplified
                         IsA Mapping 	# Mapping between coordinate systems
                            Nsla = 1 	# Number of conversion steps
                            Sla1 = "GALEQ" 	# Galactic (IAU 1958) to J2000.0 equatorial (FK5)
